// MARK: - TradingService.swift
import Foundation
import Combine

enum TradingError: Error, LocalizedError {
    case insufficientFunds
    case insufficientShares
    case networkError(Error)
    case invalidResponse
    case unknown

    var errorDescription: String? {
        switch self {
        case .insufficientFunds:
            return "Insufficient funds to complete the purchase."
        case .insufficientShares:
            return "Insufficient shares to complete the sale."
        case .networkError(let error):
            return "Network error: \(error.localizedDescription)"
        case .invalidResponse:
            return "Invalid response from the server."
        case .unknown:
            return "An unknown error occurred."
        }
    }
}

class TradingService: ObservableObject {
    @Published var marketStocks: [Stock] = []
    @Published var userAccount: UserAccount
    @Published var isLoading: Bool = false
    @Published var errorMessage: String?

    private var cancellables = Set<AnyCancellable>()
    private let priceUpdateTimer = Timer.publish(every: 3, on: .main, in: .common).autoconnect()

    init() {
        // Initialize with dummy data
        _userAccount = Published(initialValue: UserAccount(balance: 10000.00, holdings: []))
        _marketStocks = Published(initialValue: Stock.sampleStocks)

        setupRealTimePriceUpdates()
        // In a real app, you'd load user data and market data from an API here
        // fetchInitialData()
    }

    // MARK: - Real-time Price Simulation
    private func setupRealTimePriceUpdates() {
        priceUpdateTimer
            .sink { [weak self] _ in
                self?.updateStockPrices()
            }
            .store(in: &cancellables)
    }

    private func updateStockPrices() {
        for i in 0..<marketStocks.count {
            let originalPrice = marketStocks[i].currentPrice
            let randomChange = Double.random(in: -2.0...2.0)
            let newPrice = max(0.01, originalPrice + randomChange) // Ensure price doesn't go below zero

            marketStocks[i].change = newPrice - originalPrice
            marketStocks[i].changePercent = (marketStocks[i].change / originalPrice) * 100
            marketStocks[i].currentPrice = newPrice
        }
    }

    // MARK: - API Communication (Simulated)
    func fetchInitialData() {
        isLoading = true
        errorMessage = nil
        // Simulate network request
        DispatchQueue.main.asyncAfter(deadline: .now() + 1.5) { [weak self] in
            self?.isLoading = false
            // In a real app, parse JSON here
            self?.marketStocks = Stock.sampleStocks
            // self?.userAccount = fetchedUserAccount
        }
    }

    func placeOrder(stock: Stock, type: TradeType, quantity: Int) async -> Result<Trade, TradingError> {
        isLoading = true
        errorMessage = nil
        // Simulate network delay
        try? await Task.sleep(nanoseconds: 1_000_000_000) // 1 second

        let cost = Double(quantity) * stock.currentPrice

        switch type {
        case .buy:
            guard userAccount.balance >= cost else {
                isLoading = false
                errorMessage = TradingError.insufficientFunds.localizedDescription
                return .failure(.insufficientFunds)
            }
            userAccount.balance -= cost
            updatePortfolioForBuy(stock: stock, quantity: quantity, price: stock.currentPrice)

        case .sell:
            guard let holdingIndex = userAccount.holdings.firstIndex(where: { $0.stockSymbol == stock.symbol }),
                  userAccount.holdings[holdingIndex].quantity >= quantity else {
                isLoading = false
                errorMessage = TradingError.insufficientShares.localizedDescription
                return .failure(.insufficientShares)
            }
            userAccount.balance += cost
            updatePortfolioForSell(stock: stock, quantity: quantity, price: stock.currentPrice)
        }

        let newTrade = Trade(stockSymbol: stock.symbol, type: type, quantity: quantity, price: stock.currentPrice, timestamp: Date())
        // In a real app, send trade to backend and get confirmation
        // For now, just return the simulated trade
        isLoading = false
        return .success(newTrade)
    }

    // MARK: - Portfolio Management
    private func updatePortfolioForBuy(stock: Stock, quantity: Int, price: Double) {
        if let index = userAccount.holdings.firstIndex(where: { $0.stockSymbol == stock.symbol }) {
            let existingHolding = userAccount.holdings[index]
            let totalCost = (existingHolding.averagePrice * Double(existingHolding.quantity)) + (price * Double(quantity))
            let totalQuantity = existingHolding.quantity + quantity
            userAccount.holdings[index].quantity = totalQuantity
            userAccount.holdings[index].averagePrice = totalCost / Double(totalQuantity)
        } else {
            userAccount.holdings.append(PortfolioHolding(stockSymbol: stock.symbol, quantity: quantity, averagePrice: price))
        }
    }

    private func updatePortfolioForSell(stock: Stock, quantity: Int, price: Double) {
        if let index = userAccount.holdings.firstIndex(where: { $0.stockSymbol == stock.symbol }) {
            userAccount.holdings[index].quantity -= quantity
            if userAccount.holdings[index].quantity <= 0 {
                userAccount.holdings.remove(at: index)
            }
        }
    }

    // MARK: - Secure API Communication Placeholder
    func performSecureAPICall(endpoint: String, method: String, body: Data?) async throws -> Data {
        guard let url = URL(string: "https://api.yourtradingplatform.com/\(endpoint)") else {
            throw TradingError.invalidResponse // Or a more specific URL error
        }

        var request = URLRequest(url: url)
        request.httpMethod = method
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")
        // Add authentication token (e.g., Bearer token)
        // request.addValue("Bearer YOUR_AUTH_TOKEN", forHTTPHeaderField: "Authorization")
        request.httpBody = body

        let (data, response) = try await URLSession.shared.data(for: request)

        guard let httpResponse = response as? HTTPURLResponse, (200...299).contains(httpResponse.statusCode) else {
            throw TradingError.networkError(NSError(domain: "API", code: (response as? HTTPURLResponse)?.statusCode ?? 0, userInfo: [NSLocalizedDescriptionKey: "Server error"]))
        }

        return data
    }
}

