// MARK: - MarketView.swift
import SwiftUI

struct MarketView: View {
    @EnvironmentObject var tradingService: TradingService

    var body: some View {
        NavigationView {
            List {
                if tradingService.isLoading {
                    ProgressView("Loading Market Data...")
                } else if let errorMessage = tradingService.errorMessage {
                    Text("Error: \(errorMessage)")
                        .foregroundColor(.red)
                } else {
                    ForEach(tradingService.marketStocks) { stock in
                        NavigationLink(destination: StockDetailView(stock: stock)) {
                            StockRow(stock: stock)
                        }
                    }
                }
            }
            .navigationTitle("Market")
        }
    }
}

struct StockRow: View {
    let stock: Stock

    var body: some View {
        HStack {
            VStack(alignment: .leading) {
                Text(stock.symbol)
                    .font(.headline)
                Text(stock.name)
                    .font(.subheadline)
                    .foregroundColor(.gray)
            }
            Spacer()
            VStack(alignment: .trailing) {
                Text(stock.currentPrice, format: .currency(code: "USD"))
                    .font(.headline)
                HStack {
                    Image(systemName: stock.change >= 0 ? "arrowtriangle.up.fill" : "arrowtriangle.down.fill")
                        .foregroundColor(stock.change >= 0 ? .green : .red)
                    Text(stock.change, format: .currency(code: "USD"))
                        .foregroundColor(stock.change >= 0 ? .green : .red)
                    Text("(\(stock.changePercent, format: .percent.precision(.fractionLength(2))))")
                        .foregroundColor(stock.change >= 0 ? .green : .red)
                }
                .font(.subheadline)
            }
        }
        .padding(.vertical, 4)
    }
}

